#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <cooperative_groups.h>

namespace cg = cooperative_groups;

// Problem 008: MoE expert-output combine.
// Fused single-kernel implementation that seeds output = final_hidden_states
// and then atomically scatters expert_outputs[rows] back to their token rows.
// A grid-wide barrier guarantees every output row is seeded before any scatter
// add touches it, eliminating the separate clone launch and its sync overhead.

__global__ void fused_scatter_add_bf16_kernel(
    __nv_bfloat16* __restrict__ out,
    const __nv_bfloat16* __restrict__ fhs,
    const __nv_bfloat16* __restrict__ eo,
    const int64_t* __restrict__ idx,
    int T,
    int N,
    int H)
{
    const int block_id = blockIdx.x;
    const int thread_id = threadIdx.x;
    const int block_dim = blockDim.x;
    const int grid_dim = gridDim.x;

    // Phase 1: seed output = final_hidden_states.
    // 8 bf16 = 16 bytes per thread (float4) for full memory-width copies.
    const int total_out = T * H;
    const int seed_vec = total_out >> 3;          // number of float4 elements
    const int total_threads = grid_dim * block_dim;
    const int gid = block_id * block_dim + thread_id;

    for (int i = gid; i < seed_vec; i += total_threads) {
        reinterpret_cast<float4*>(out)[i] = reinterpret_cast<const float4*>(fhs)[i];
    }

    // Every token row must be visible before any atomic add is issued.
    cg::this_grid().sync();

    // Phase 2: scatter-add expert outputs.
    // Each block owns a contiguous slice of expert-output rows.
    const int rows_per_block = (N + grid_dim - 1) / grid_dim;
    const int row_begin = block_id * rows_per_block;
    const int row_end = min(row_begin + rows_per_block, N);
    const int cols_per_row = H >> 1;              // number of bf16x2 per row

    for (int row = row_begin; row < row_end; ++row) {
        const int64_t out_row = idx[row];
        const __nv_bfloat162* eo_row_ptr =
            reinterpret_cast<const __nv_bfloat162*>(eo + row * H);
        __nv_bfloat162* out_row_ptr =
            reinterpret_cast<__nv_bfloat162*>(out + out_row * H);

        for (int c = thread_id; c < cols_per_row; c += block_dim) {
            __nv_bfloat162 val = eo_row_ptr[c];
            atomicAdd(&out_row_ptr[c], val);
        }
    }
}

static void fallback_run(
    torch::Tensor& output,
    const torch::Tensor& final_hidden_states,
    const torch::Tensor& expert_outputs,
    const torch::Tensor& token_indices)
{
    output.copy_(final_hidden_states);
    output.index_add_(0, token_indices, expert_outputs);
}

torch::Tensor run(
    torch::Tensor final_hidden_states,
    torch::Tensor expert_outputs,
    torch::Tensor token_indices)
{
    const bool can_fast_path =
        final_hidden_states.is_cuda() &&
        final_hidden_states.scalar_type() == at::kBFloat16 &&
        expert_outputs.scalar_type() == at::kBFloat16 &&
        token_indices.dtype() == at::kLong &&
        final_hidden_states.dim() == 2 &&
        expert_outputs.dim() == 2 &&
        token_indices.dim() == 1 &&
        final_hidden_states.is_contiguous() &&
        expert_outputs.is_contiguous() &&
        final_hidden_states.size(1) == 3072 &&
        expert_outputs.size(1) == 3072;

    auto output = torch::empty_like(final_hidden_states);

    if (!can_fast_path) {
        fallback_run(output, final_hidden_states, expert_outputs, token_indices);
        return output;
    }

    const int T = static_cast<int>(final_hidden_states.size(0));
    const int H = static_cast<int>(final_hidden_states.size(1));
    const int N = static_cast<int>(expert_outputs.size(0));

    if (N == 0) {
        fallback_run(output, final_hidden_states, expert_outputs, token_indices);
        return output;
    }

    // Fixed cooperative grid tuned to fit concurrently on B200 while giving
    // each block enough rows to amortize loop overhead on large shapes.
    const int block_size = 128;
    const int grid_size = 1024;

    const int device = final_hidden_states.device().index();
    int num_sms = 0;
    int max_blocks_per_sm = 0;

    cudaError_t err = cudaDeviceGetAttribute(&num_sms, cudaDevAttrMultiProcessorCount, device);
    if (err != cudaSuccess) {
        fallback_run(output, final_hidden_states, expert_outputs, token_indices);
        return output;
    }

    err = cudaOccupancyMaxActiveBlocksPerMultiprocessor(
        &max_blocks_per_sm, fused_scatter_add_bf16_kernel, block_size, 0);
    if (err != cudaSuccess) {
        fallback_run(output, final_hidden_states, expert_outputs, token_indices);
        return output;
    }

    const int max_coop_grid = max_blocks_per_sm * num_sms;
    if (grid_size > max_coop_grid) {
        fallback_run(output, final_hidden_states, expert_outputs, token_indices);
        return output;
    }

    auto out_ptr = output.data_ptr<__nv_bfloat16>();
    auto fhs_ptr = final_hidden_states.data_ptr<__nv_bfloat16>();
    auto eo_ptr = expert_outputs.data_ptr<__nv_bfloat16>();
    auto idx_ptr = token_indices.data_ptr<int64_t>();

    void* args[] = {
        &out_ptr,
        &fhs_ptr,
        &eo_ptr,
        &idx_ptr,
        &T,
        &N,
        &H,
    };

    err = cudaLaunchCooperativeKernel(
        reinterpret_cast<void*>(fused_scatter_add_bf16_kernel),
        dim3(grid_size),
        dim3(block_size),
        args,
        0,
        at::cuda::getCurrentCUDAStream(device).stream());

    if (err != cudaSuccess) {
        fallback_run(output, final_hidden_states, expert_outputs, token_indices);
        return output;
    }

    return output;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Problem 008 fused expert-output scatter-add");
}

#include <ATen/cuda/CUDAContext.h>
#include <c10/cuda/CUDAGuard.h>
#include <c10/cuda/CUDAException.h>
#include <cooperative_groups.h>
#include <cuda_bf16.h>
#include <cuda_runtime.h>
#include <torch/extension.h>

#include <algorithm>
#include <cstdint>

namespace {

constexpr int kHidden = 3072;
constexpr int kHiddenPairs = kHidden / 2;
constexpr int kBlockThreads = 256;
constexpr int kTargetBlocksPerSm = 4;

__global__ void seed_then_scatter_kernel(
    const __nv_bfloat162* __restrict__ final_hidden_states,
    const __nv_bfloat162* __restrict__ expert_outputs,
    const int64_t* __restrict__ token_indices,
    __nv_bfloat162* __restrict__ output,
    int64_t num_tokens,
    int64_t num_selected_tokens) {
  cooperative_groups::grid_group grid = cooperative_groups::this_grid();

  const int64_t tid =
      static_cast<int64_t>(blockIdx.x) * blockDim.x + threadIdx.x;
  const int64_t stride =
      static_cast<int64_t>(gridDim.x) * blockDim.x;

  const int64_t total_pairs = num_tokens * kHiddenPairs;
  for (int64_t pair = tid; pair < total_pairs; pair += stride) {
    output[pair] = final_hidden_states[pair];
  }

  grid.sync();

  for (int64_t row = blockIdx.x; row < num_selected_tokens; row += gridDim.x) {
    const int64_t token = token_indices[row];
    const int64_t in_base = row * kHiddenPairs;
    const int64_t out_base = token * kHiddenPairs;

    #pragma unroll
    for (int col = threadIdx.x; col < kHiddenPairs; col += kBlockThreads) {
      const __nv_bfloat162 value = expert_outputs[in_base + col];
      atomicAdd(output + out_base + col, value);
    }
  }
}

torch::Tensor fallback_index_add(
    torch::Tensor final_hidden_states,
    torch::Tensor expert_outputs,
    torch::Tensor token_indices) {
  torch::Tensor output = final_hidden_states.clone();
  output.index_add_(0, token_indices, expert_outputs);
  return output;
}

}  // namespace

torch::Tensor run(
    torch::Tensor final_hidden_states,
    torch::Tensor expert_outputs,
    torch::Tensor token_indices) {
  if (!final_hidden_states.is_cuda() ||
      final_hidden_states.scalar_type() != torch::kBFloat16 ||
      expert_outputs.scalar_type() != torch::kBFloat16 ||
      token_indices.scalar_type() != torch::kInt64 ||
      final_hidden_states.dim() != 2 ||
      expert_outputs.dim() != 2 ||
      token_indices.dim() != 1 ||
      final_hidden_states.size(1) != kHidden ||
      expert_outputs.size(1) != kHidden ||
      !final_hidden_states.is_contiguous() ||
      !expert_outputs.is_contiguous() ||
      !token_indices.is_contiguous()) {
    return fallback_index_add(final_hidden_states, expert_outputs, token_indices);
  }

  c10::cuda::CUDAGuard device_guard(final_hidden_states.device());

  int64_t num_tokens = final_hidden_states.size(0);
  int64_t num_selected_tokens = expert_outputs.size(0);

  cudaDeviceProp prop;
  C10_CUDA_CHECK(cudaGetDeviceProperties(
      &prop, static_cast<int>(final_hidden_states.get_device())));

  if (!prop.cooperativeLaunch) {
    return fallback_index_add(final_hidden_states, expert_outputs, token_indices);
  }

  torch::Tensor output = torch::empty_like(final_hidden_states);

  int max_active_blocks_per_sm = 0;
  C10_CUDA_CHECK(cudaOccupancyMaxActiveBlocksPerMultiprocessor(
      &max_active_blocks_per_sm,
      seed_then_scatter_kernel,
      kBlockThreads,
      0));

  const int blocks_per_sm =
      std::max(1, std::min(max_active_blocks_per_sm, kTargetBlocksPerSm));
  const int grid_blocks = std::max(1, prop.multiProcessorCount * blocks_per_sm);

  const __nv_bfloat162* fhs_ptr =
      reinterpret_cast<const __nv_bfloat162*>(final_hidden_states.data_ptr());
  const __nv_bfloat162* eo_ptr =
      reinterpret_cast<const __nv_bfloat162*>(expert_outputs.data_ptr());
  const int64_t* idx_ptr =
      reinterpret_cast<const int64_t*>(token_indices.data_ptr());
  __nv_bfloat162* out_ptr =
      reinterpret_cast<__nv_bfloat162*>(output.data_ptr());

  void* args[] = {
      &fhs_ptr,
      &eo_ptr,
      &idx_ptr,
      &out_ptr,
      &num_tokens,
      &num_selected_tokens};

  cudaStream_t stream = at::cuda::getCurrentCUDAStream().stream();
  C10_CUDA_CHECK(cudaLaunchCooperativeKernel(
      reinterpret_cast<void*>(seed_then_scatter_kernel),
      dim3(grid_blocks),
      dim3(kBlockThreads),
      args,
      0,
      stream));

  return output;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "B200 cooperative BF16 MoE index-add");
}
